<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Ubuntu Desktop</title>
<style>
  * { margin: 0; padding: 0; box-sizing: border-box; }
  html, body { height: 100%; overflow: hidden; }
  body {
    font-family: "Ubuntu", "Segoe UI", "Noto Sans", sans-serif;
    background: #2c001e;
    color: #eee;
    user-select: none;
  }

  /* ---------- Desktop ---------- */
  #desktop {
    position: fixed;
    inset: 0;
    background:
      radial-gradient(ellipse at 20% 110%, rgba(233,84,32,.55), transparent 55%),
      radial-gradient(ellipse at 85% -10%, rgba(119,33,111,.75), transparent 60%),
      linear-gradient(135deg, #3b0f2e 0%, #2c001e 45%, #1d0a17 100%);
    overflow: hidden;
  }
  #desktop::after {
    /* subtle noise-ish vignette */
    content: "";
    position: absolute; inset: 0;
    background: radial-gradient(ellipse at 50% 45%, transparent 55%, rgba(0,0,0,.35) 100%);
    pointer-events: none;
  }

  /* ---------- Top bar ---------- */
  #topbar {
    position: absolute;
    top: 0; left: 0; right: 0;
    height: 32px;
    background: rgba(20, 20, 24, .92);
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0 14px;
    font-size: 13px;
    z-index: 5000;
    box-shadow: 0 1px 6px rgba(0,0,0,.4);
  }
  #topbar .tb-left { font-weight: 700; letter-spacing: .3px; color: #f4f4f4; }
  #topbar .tb-center { color: #ddd; }
  #topbar .tb-right { display: flex; gap: 12px; color: #ccc; font-size: 12px; }

  /* ---------- Dock / taskbar ---------- */
  #taskbar {
    position: absolute;
    left: 0;
    top: 32px;
    bottom: 0;
    width: 68px;
    background: rgba(18, 18, 22, .82);
    backdrop-filter: blur(6px);
    display: flex;
    flex-direction: column;
    align-items: center;
    padding-top: 14px;
    gap: 12px;
    z-index: 4000;
    box-shadow: 1px 0 8px rgba(0,0,0,.35);
  }
  .launcher {
    width: 50px;
    height: 50px;
    border: none;
    border-radius: 12px;
    cursor: pointer;
    background: rgba(255,255,255,.06);
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    gap: 2px;
    color: #eee;
    font-size: 9px;
    transition: background .15s, transform .1s;
  }
  .launcher:hover { background: rgba(255,255,255,.16); transform: scale(1.06); }
  .launcher:active { transform: scale(.97); }
  .launcher .glyph { font-size: 22px; line-height: 1; }

  /* ---------- Windows ---------- */
  .window {
    position: absolute;
    min-width: 360px;
    min-height: 240px;
    width: 560px;
    height: 400px;
    background: #262630;
    border-radius: 10px;
    box-shadow: 0 14px 40px rgba(0,0,0,.55), 0 0 0 1px rgba(255,255,255,.08);
    display: flex;
    flex-direction: column;
    overflow: hidden;
    z-index: 100;
  }
  .window.hidden { display: none; }
  .titlebar {
    height: 36px;
    flex: 0 0 36px;
    background: linear-gradient(#3a3a44, #30303a);
    display: flex;
    align-items: center;
    padding: 0 10px;
    cursor: grab;
    gap: 8px;
  }
  .titlebar:active { cursor: grabbing; }
  .titlebar .title {
    flex: 1;
    text-align: center;
    font-size: 13px;
    font-weight: 500;
    color: #ddd;
    pointer-events: none;
  }
  .win-close {
    width: 22px;
    height: 22px;
    border: none;
    border-radius: 50%;
    background: #e95420;
    color: #fff;
    font-size: 12px;
    line-height: 1;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    transition: filter .15s;
  }
  .win-close:hover { filter: brightness(1.2); }
  .win-body {
    flex: 1;
    display: flex;
    flex-direction: column;
    min-height: 0;
    background: #1f1f27;
  }

  /* ---------- Files app ---------- */
  #files-toolbar {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 8px 10px;
    background: #2b2b35;
    border-bottom: 1px solid rgba(255,255,255,.07);
  }
  #files-up {
    border: none;
    background: rgba(255,255,255,.1);
    color: #eee;
    border-radius: 6px;
    padding: 5px 12px;
    cursor: pointer;
    font-size: 14px;
  }
  #files-up:hover { background: rgba(255,255,255,.2); }
  #files-path {
    flex: 1;
    background: #17171d;
    border-radius: 6px;
    padding: 6px 10px;
    font-family: "Ubuntu Mono", Consolas, monospace;
    font-size: 13px;
    color: #9fd7a0;
    white-space: nowrap;
    overflow-x: auto;
  }
  #files-list {
    flex: 1;
    overflow-y: auto;
    padding: 10px;
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(96px, 1fr));
    gap: 8px;
    align-content: start;
  }
  .fs-item {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 4px;
    padding: 10px 4px;
    border-radius: 8px;
    cursor: pointer;
    font-size: 12px;
    text-align: center;
    word-break: break-all;
    color: #e8e8e8;
  }
  .fs-item:hover { background: rgba(255,255,255,.08); }
  .fs-item .icon { font-size: 30px; line-height: 1; pointer-events: none; }
  .fs-item .icon.folder { color: #e95420; }
  .fs-empty { grid-column: 1/-1; color: #888; font-size: 13px; padding: 20px; text-align: center; }

  /* ---------- Notepad app ---------- */
  #notepad-toolbar {
    display: flex;
    align-items: stretch;
    background: #2b2b35;
    border-bottom: 1px solid rgba(255,255,255,.07);
    padding: 6px 8px 0 8px;
    gap: 4px;
  }
  #tabs {
    display: flex;
    gap: 4px;
    flex: 1;
    overflow-x: auto;
    min-width: 0;
  }
  .tab {
    display: flex;
    align-items: center;
    gap: 6px;
    padding: 6px 12px;
    background: #34343f;
    border-radius: 8px 8px 0 0;
    font-size: 12px;
    cursor: pointer;
    white-space: nowrap;
    color: #bbb;
    max-width: 160px;
  }
  .tab .tab-name { overflow: hidden; text-overflow: ellipsis; pointer-events: none; }
  .tab.active { background: #17171d; color: #fff; }
  .tab .tab-x {
    font-size: 11px;
    color: #888;
    border-radius: 50%;
    width: 15px; height: 15px;
    display: flex; align-items: center; justify-content: center;
    flex: 0 0 15px;
  }
  .tab .tab-x:hover { background: rgba(255,255,255,.15); color: #fff; }
  #new-tab {
    border: none;
    background: rgba(255,255,255,.1);
    color: #eee;
    border-radius: 6px;
    width: 28px;
    height: 28px;
    align-self: center;
    cursor: pointer;
    font-size: 16px;
    flex: 0 0 28px;
  }
  #new-tab:hover { background: rgba(255,255,255,.22); }
  #editor {
    flex: 1;
    width: 100%;
    resize: none;
    border: none;
    outline: none;
    background: #17171d;
    color: #eaeaea;
    font-family: "Ubuntu Mono", Consolas, monospace;
    font-size: 14px;
    line-height: 1.5;
    padding: 12px;
    user-select: text;
  }
</style>
</head>
<body>
<div id="desktop">
  <div id="topbar">
    <span class="tb-left">Activities</span>
    <span class="tb-center" id="clock">—</span>
    <span class="tb-right"><span>⏻</span><span>🔊</span><span>🔋</span></span>
  </div>

  <div id="taskbar">
    <button class="launcher" id="open-files" title="Files">
      <span class="glyph">🗂️</span><span>Files</span>
    </button>
    <button class="launcher" id="open-notepad" title="Notepad">
      <span class="glyph">📝</span><span>Notepad</span>
    </button>
  </div>

  <!-- Files window -->
  <div class="window hidden" id="files-window" style="left:140px; top:80px; width:600px; height:420px;">
    <div class="titlebar">
      <span class="title">Files</span>
      <button class="win-close" title="Close">✕</button>
    </div>
    <div class="win-body">
      <div id="files-toolbar">
        <button id="files-up" title="Up one level">⬆</button>
        <div id="files-path">/</div>
      </div>
      <div id="files-list"></div>
    </div>
  </div>

  <!-- Notepad window -->
  <div class="window hidden" id="notepad-window" style="left:280px; top:140px; width:580px; height:400px;">
    <div class="titlebar">
      <span class="title">Notepad</span>
      <button class="win-close" title="Close">✕</button>
    </div>
    <div class="win-body">
      <div id="notepad-toolbar">
        <div id="tabs"></div>
        <button id="new-tab" title="New tab">＋</button>
      </div>
      <textarea id="editor" spellcheck="false" placeholder="Start typing…"></textarea>
    </div>
  </div>
</div>

<script>
(function () {
  "use strict";

  /* ============ Clock ============ */
  const clock = document.getElementById("clock");
  function tick() {
    const d = new Date();
    clock.textContent = d.toLocaleDateString(undefined, { weekday: "short", month: "short", day: "numeric" })
      + "  " + d.toLocaleTimeString(undefined, { hour: "2-digit", minute: "2-digit" });
  }
  tick();
  setInterval(tick, 15000);

  /* ============ Window management ============ */
  let zTop = 100;
  function bringToFront(win) { win.style.zIndex = ++zTop; }

  function openWindow(win) {
    win.classList.remove("hidden");
    // keep window within the viewport
    const dr = document.getElementById("desktop").getBoundingClientRect();
    const r = win.getBoundingClientRect();
    if (r.right > dr.width) win.style.left = Math.max(70, dr.width - r.width - 10) + "px";
    if (r.bottom > dr.height) win.style.top = Math.max(34, dr.height - r.height - 10) + "px";
    bringToFront(win);
  }

  document.querySelectorAll(".window").forEach(win => {
    win.addEventListener("mousedown", () => bringToFront(win));
    win.querySelector(".win-close").addEventListener("click", e => {
      e.stopPropagation();
      win.classList.add("hidden");
    });
    // dragging via titlebar
    const bar = win.querySelector(".titlebar");
    bar.addEventListener("mousedown", e => {
      if (e.target.closest(".win-close")) return;
      e.preventDefault();
      const startX = e.clientX, startY = e.clientY;
      const origL = win.offsetLeft, origT = win.offsetTop;
      function move(ev) {
        win.style.left = (origL + ev.clientX - startX) + "px";
        win.style.top = Math.max(32, origT + ev.clientY - startY) + "px";
      }
      function up() {
        document.removeEventListener("mousemove", move);
        document.removeEventListener("mouseup", up);
      }
      document.addEventListener("mousemove", move);
      document.addEventListener("mouseup", up);
    });
  });

  const filesWin = document.getElementById("files-window");
  const notepadWin = document.getElementById("notepad-window");
  document.getElementById("open-files").addEventListener("click", () => { openWindow(filesWin); renderFiles(); });
  document.getElementById("open-notepad").addEventListener("click", () => { openWindow(notepadWin); renderNotepad(); });

  /* ============ Files app ============ */
  // Fake filesystem: folders are objects, files are strings.
  const FS = {
    bin: { bash: "", ls: "", cat: "", grep: "", cp: "", mv: "", nano: "" },
    boot: { "vmlinuz-6.8.0-40-generic": "", "initrd.img": "", grub: { "grub.cfg": "" } },
    etc: {
      hostname: "", hosts: "", fstab: "", passwd: "", "os-release": "",
      apt: { "sources.list": "" },
      ssh: { sshd_config: "" }
    },
    home: {
      user: {
        Documents: { "resume.pdf": "", "notes.txt": "", projects: { "todo.md": "", "ideas.md": "" } },
        Downloads: { "ubuntu-24.04.iso": "", "photo.zip": "" },
        Pictures: { "wallpaper.png": "", "screenshot.png": "", Vacation: { "beach.jpg": "" } },
        Music: {},
        Videos: {},
        ".bashrc": "",
        ".profile": ""
      }
    },
    lib: { systemd: {}, modules: {} },
    opt: {},
    root: {},
    tmp: {},
    usr: {
      bin: { python3: "", gcc: "", vim: "" },
      lib: {},
      local: { bin: {} },
      share: { doc: {}, icons: {} }
    },
    var: { log: { syslog: "", "auth.log": "", "kern.log": "" }, cache: {}, www: { html: { "index.html": "" } } }
  };

  let cwd = []; // array of path segments; [] = "/"
  const filesPath = document.getElementById("files-path");
  const filesList = document.getElementById("files-list");

  function nodeAt(segs) {
    let n = FS;
    for (const s of segs) n = n[s];
    return n;
  }

  function renderFiles() {
    filesPath.textContent = "/" + cwd.join("/");
    filesList.innerHTML = "";
    const node = nodeAt(cwd);
    const names = Object.keys(node).sort((a, b) => {
      const da = typeof node[a] === "object", db = typeof node[b] === "object";
      if (da !== db) return da ? -1 : 1; // folders first
      return a.localeCompare(b);
    });
    if (!names.length) {
      const empty = document.createElement("div");
      empty.className = "fs-empty";
      empty.textContent = "This folder is empty";
      filesList.appendChild(empty);
      return;
    }
    for (const name of names) {
      const isDir = typeof node[name] === "object";
      const el = document.createElement("div");
      el.className = "fs-item";
      el.title = isDir ? "Double-click to open" : name;

      const icon = document.createElement("span");
      icon.className = "icon" + (isDir ? " folder" : "");
      icon.textContent = isDir ? "📁" : "📄";
      el.appendChild(icon);
      el.appendChild(document.createTextNode(name));

      if (isDir) {
        el.addEventListener("dblclick", () => {
          cwd.push(name);
          renderFiles();
        });
      }
      filesList.appendChild(el);
    }
  }

  document.getElementById("files-up").addEventListener("click", () => {
    if (cwd.length) {
      cwd.pop();
      renderFiles();
    }
  });

  renderFiles();

  /* ============ Notepad app ============ */
  const LS_KEY = "notepad-tabs-v1";
  const tabsEl = document.getElementById("tabs");
  const editor = document.getElementById("editor");

  let state;
  function loadState() {
    try {
      const raw = localStorage.getItem(LS_KEY);
      if (raw) {
        const parsed = JSON.parse(raw);
        if (parsed && Array.isArray(parsed.tabs) && parsed.tabs.length) {
          state = parsed;
          if (!state.tabs.some(t => t.id === state.active)) state.active = state.tabs[0].id;
          return;
        }
      }
    } catch (e) { /* corrupted storage — start fresh */ }
    state = { tabs: [{ id: 1, title: "Untitled 1", content: "" }], active: 1, nextId: 2 };
    saveState();
  }
  function saveState() {
    localStorage.setItem(LS_KEY, JSON.stringify(state));
  }
  function activeTab() {
    return state.tabs.find(t => t.id === state.active) || state.tabs[0];
  }

  function renderNotepad() {
    tabsEl.innerHTML = "";
    for (const t of state.tabs) {
      const tab = document.createElement("div");
      tab.className = "tab" + (t.id === state.active ? " active" : "");
      tab.dataset.id = t.id;

      const name = document.createElement("span");
      name.className = "tab-name";
      name.textContent = t.title;
      tab.appendChild(name);

      if (state.tabs.length > 1) {
        const x = document.createElement("span");
        x.className = "tab-x";
        x.textContent = "✕";
        x.title = "Close tab";
        x.addEventListener("click", ev => {
          ev.stopPropagation();
          const idx = state.tabs.findIndex(tt => tt.id === t.id);
          state.tabs.splice(idx, 1);
          if (state.active === t.id) {
            state.active = state.tabs[Math.max(0, idx - 1)].id;
          }
          saveState();
          renderNotepad();
        });
        tab.appendChild(x);
      }

      tab.addEventListener("click", () => {
        state.active = t.id;
        saveState();
        renderNotepad();
      });
      tabsEl.appendChild(tab);
    }
    editor.value = activeTab().content;
  }

  document.getElementById("new-tab").addEventListener("click", () => {
    const id = state.nextId || (Math.max(...state.tabs.map(t => t.id)) + 1);
    state.nextId = id + 1;
    state.tabs.push({ id, title: "Untitled " + id, content: "" });
    state.active = id;
    saveState();
    renderNotepad();
    editor.focus();
  });

  editor.addEventListener("input", () => {
    const t = activeTab();
    t.content = editor.value;
    // derive tab title from first line, keep "Untitled N" when empty
    const firstLine = editor.value.split("\n")[0].trim();
    t.title = firstLine ? firstLine.slice(0, 20) : "Untitled " + t.id;
    saveState();
    const tabEl = tabsEl.querySelector('.tab[data-id="' + t.id + '"] .tab-name');
    if (tabEl) tabEl.textContent = t.title;
  });

  loadState();
  renderNotepad();
})();
</script>
</body>
</html>
